// // This module is designed to compute the output X based on inputs A1, A2, B1, B2, and C1. It uses two OR gates to determine the intermediate signals: one OR gate evaluates the inputs B1 and B2, while the other evaluates A1 and A2. The outputs of these OR gates are then combined using an AND gate along with the input C1 to produce the final output X. This structure allows for flexibility in logical evaluation, effectively integrating multiple logical conditions.
module top_module(
    input A1,
    input A2,
    input B1,
    input B2,
    input C1,
    output X
);// Internal signals
    wire and0_out;
    wire and1_out;
    wire or0_out_X;

    // Logic gates
    and and0 (and0_out, B1, B2);
    and and1 (and1_out, A1, A2);
    or or0 (or0_out_X, and1_out, and0_out, C1);

    // Output
    assign X = or0_out_X;

endmodule
